class Solution:
    def score(self, cards, x):
        from collections import Counter
        cnt = Counter(cards)
        xx = cnt.get(x + x, 0)
        A = {}
        B = {}
        for c, n in cnt.items():
            if x not in c or c == x + x:
                continue
            if c[0] == x:
                A[c[1]] = A.get(c[1], 0) + n
            elif c[1] == x:
                B[c[0]] = B.get(c[0], 0) + n
        va = list(A.values())
        vb = list(B.values())
        def pair_group(vals, wild):
            groups = [v for v in vals if v > 0]
            if wild > 0:
                groups.append(wild)
            total = sum(groups)
            mx = max(groups) if groups else 0
            return min(total // 2, total - mx)
        best = 0
        for split in range(xx + 1):
            best = max(best, pair_group(va, split) + pair_group(vb, xx - split))
        return best

