var score = function(cards, x) {
    const cnt = new Map();
    for (const c of cards) cnt.set(c, (cnt.get(c) || 0) + 1);
    const xx = cnt.get(x + x) || 0;
    const A = new Map();
    const B = new Map();
    for (const [c, n] of cnt) {
        if (!c.includes(x) || c === x + x) continue;
        if (c[0] === x) A.set(c[1], (A.get(c[1]) || 0) + n);
        else if (c[1] === x) B.set(c[0], (B.get(c[0]) || 0) + n);
    }
    const va = [...A.values()];
    const vb = [...B.values()];
    const pairGroup = (vals, wild) => {
        const groups = vals.filter(v => v > 0);
        if (wild > 0) groups.push(wild);
        const total = groups.reduce((a, b) => a + b, 0);
        const mx = groups.length ? Math.max(...groups) : 0;
        return Math.min(Math.floor(total / 2), total - mx);
    };
    let best = 0;
    for (let split = 0; split <= xx; split++) {
        best = Math.max(best, pairGroup(va, split) + pairGroup(vb, xx - split));
    }
    return best;
};
